package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Construct the ping command.
	// Note: The original code used single quotes within the shell command which can cause issues
	// on some systems. It is safer to pass arguments directly to exec.Command.
	// The flags used are:
	// -c <count>: Stop after sending (and receiving) <count> ECHO_REQUEST packets.
	// -W <timeout>: Time to wait for a response in seconds (set to 1 to avoid hanging).
	// -s <size>: Specify the number of data bytes to be sent (set to 56 to match standard ping).
	// Note: The exact flags might vary slightly depending on the OS (Linux vs macOS vs Windows).
	// This implementation targets standard Linux ping behavior.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", "-s", "56", host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the error is because the command was not found
		if errors.Is(err, exec.ErrNotFound) {
			return 0, fmt.Errorf("ping command not found: %w", err)
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Standard Linux ping output format contains "rtt min/avg/max/mdev"
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We capture the second group (the average value).
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		// Fallback: Try to parse the line if the standard format isn't found exactly
		// Sometimes the format might vary slightly (e.g., no mdev).
		// Let's try a more generic regex for the average value.
		genericRe := regexp.MustCompile(`=\s*[\d.]+\s*/\s*([\d.]+)\s*/`)
		matches = genericRe.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
		}
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4
	fmt.Printf("Pinging %s %d times...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", latency)
}

