package main

import (
    "bufio"
    "errors"
    "fmt"
    "os/exec"
    "regexp"
    "strconv"
    "strings"
)

// MeasureLatency pings the specified host 'count' times and returns the average latency in milliseconds.
// It uses the system's 'ping' command.
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, errors.New("count must be a positive integer")
    }

    // Construct the ping command arguments.
    // -c: number of packets
    // -s: packet size (64 bytes is standard)
    // The output format varies by OS, so we parse standard output lines.
    args := []string{"-c", strconv.Itoa(count), "-s", "64", host}

    cmd := exec.Command("ping", args...)

    output, err := cmd.CombinedOutput()
    if err != nil {
        // If the command fails, return the error.
        return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, string(output))
    }

    return parsePingOutput(string(output), count)
}

// parsePingOutput parses the standard output of the ping command to extract latencies.
// It looks for lines containing "time=" followed by a number (float or int).
func parsePingOutput(output string, expectedCount int) (float64, error) {
    scanner := bufio.NewScanner(strings.NewReader(output))

    // Regex to match "time=12.3" or "time=45" (ms)
    // It handles both dot and comma as decimal separators depending on locale, 
    // though standard ping usually uses a dot.
    re := regexp.MustCompile(`time[=:]?\s*([\d,\.]+)\s*ms`)

    var sum float64
    var matchCount int

    for scanner.Scan() {
        line := scanner.Text()
        matches := re.FindStringSubmatch(line)
        if len(matches) > 1 {
            // Replace comma with dot for parsing if locale uses comma
            valStr := strings.ReplaceAll(matches[1], ",", ".")
            val, err := strconv.ParseFloat(valStr, 64)
            if err == nil {
                sum += val
                matchCount++
            }
        }
    }

    if err := scanner.Err(); err != nil {
        return 0, fmt.Errorf("error reading ping output: %w", err)
    }

    if matchCount == 0 {
        return 0, errors.New("no latency data found in ping output")
    }

    // Return the average
    return sum / float64(matchCount), nil
}

