package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use Command instead of bash -c to avoid shell injection vulnerabilities
	// Pass arguments directly to the ping command
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the error is specifically because ping is not found
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping command failed with exit code %d: %w (output: %s)", exitErr.ExitCode(), err, string(output))
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Check for both Linux and macOS ping output formats
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example lines:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|min/avg/max|round-trip).*? = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avgLatency)
}

