package main

import (
    "bufio"
    "fmt"
    "os"
    "os/exec"
    "regexp"
    "runtime"
    "strconv"
    "strings"
)

// MeasureLatency pings the specified host 'count' times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, fmt.Errorf("count must be positive")
    }

    // Determine the correct flag for count based on the operating system.
    // Windows uses -n, Unix-like systems (Linux, macOS) use -c.
    countFlag := "-c"
    if runtime.GOOS == "windows" {
        countFlag = "-n"
    }

    // Construct arguments
    // Windows: ping -n <count> <host>
    // Linux/macOS: ping -c <count> <host>
    args := []string{countFlag, strconv.Itoa(count), host}

    // Execute the ping command
    cmd := exec.Command("ping", args...)

    // Capture the output
    output, err := cmd.CombinedOutput()
    if err != nil {
        return 0, fmt.Errorf("ping command failed: %v", err)
    }

    // Regex to extract time=XX.X ms or time=XXms
    // Linux: time=XX.X ms
    // Windows: time=XXms
    var re *regexp.Regexp
    if runtime.GOOS == "windows" {
        re = regexp.MustCompile(`time[=<](\d+)ms`)
    } else {
        re = regexp.MustCompile(`time[=<]([\d.]+)ms`)
    }

    // Find all matches
    matches := re.FindAllStringSubmatch(string(output), -1)
    if len(matches) == 0 {
        return 0, fmt.Errorf("no latency data found in ping output")
    }

    // Sum latencies
    var sum float64
    for _, match := range matches {
        if len(match) < 2 {
            continue
        }
        val, err := strconv.ParseFloat(match[1], 64)
        if err == nil {
            sum += val
        }
    }

    if len(matches) == 0 {
        return 0, fmt.Errorf("failed to parse latency values")
    }

    return sum / float64(len(matches)), nil
}

func main() {
    // Example usage
    if len(os.Args) < 3 {
        fmt.Println("Usage: go run main.go <host> <count>")
        return
    }

    host := os.Args[1]
    countStr := os.Args[2]

    count, err := strconv.Atoi(countStr)
    if err != nil {
        fmt.Printf("Invalid count: %v\n", err)
        return
    }

    avg, err := MeasureLatency(host, count)
    if err != nil {
        fmt.Printf("Error measuring latency: %v\n", err)
        return
    }

    fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

