	return parsePingOutput(out.String(), false)
}

// parsePingOutput parses the output string of the ping command.
// isWindows determines the parsing logic (Windows vs Unix output format).
func parsePingOutput(output string, isWindows bool) (float64, error) {
	scanner := bufio.NewScanner(bytes.NewBufferString(output))
	var latencies []float64

	// Regex to extract time value from standard output
	// Matches: time=12.3 ms or time=12.3
	var timeRegex *regexp.Regexp
	if isWindows {
