// MeasureLatency executes the ping command to a specified host a specific number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, errors.New("count must be a positive integer")
    }

    var cmd *exec.Cmd

    // Check the operating system to determine the correct ping flags
    if runtime.GOOS == "windows" {
        // Windows: ping -n <count> -w 1000 <host>
        // -w 1000 sets timeout to 1000ms (1 second) per packet
        cmd = exec.Command("ping", "-n", strconv.Itoa(count), "-w", "1000", host)
    } else {
        // Linux/macOS: ping -c <count> -W 1 <host>
        // -W 1 sets timeout to 1 second per packet
        cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)
    }

    // Execute the command and capture output
    outputBytes, err := cmd.CombinedOutput()
    if err != nil {
        // If the command fails (e.g., host unreachable), return the error
        return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, string(outputBytes))
    }

    output := string(outputBytes)

    // Parse the output to find the average latency
    var avgLatency float64
    var found bool

    if runtime.GOOS == "windows" {
        // Windows pattern: Average = 32ms
        re := regexp.MustCompile(`Average\s*=\s*([\d.]+)ms`)
        matches := re.FindStringSubmatch(output)
        if len(matches) < 2 {
            return 0, errors.New("could not parse average latency from Windows ping output")
        }
        val, err := strconv.ParseFloat(matches[1], 64)
        if err != nil {
