	}

	// Execute the ping command
	cmd := exec.Command("ping", args...)

	// Capture both stdout and stderr to handle output correctly
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	err := cmd.Run()
	if err != nil {
		// Ping returns exit code 1 if packets are lost, but we might still want to parse partial results.
		// However, if the command itself fails (e.g., ping not found, invalid arguments), return error.
		// We check if output is empty to distinguish execution failure from packet loss.
		if out.Len() == 0 {
