		}
		// Continue to parse output even if error is returned (e.g., packet loss)
	}

	// Parse the output to find latency values
	scanner := bufio.NewScanner(&out)
	var latencies []float64

	// Regex to match latency in the format "time=X ms" (Unix) or "time=Xms" (Windows)
