// parsePingOutput analyzes the ping output string to extract the average round-trip time.
func parsePingOutput(output string) (float64, error) {
    scanner := bufio.NewScanner(strings.NewReader(output))
    var lastLine string

    // Find the statistics summary line (usually the last line containing "average")
    for scanner.Scan() {
        line := scanner.Text()
        if strings.Contains(strings.ToLower(line), "average") || strings.Contains(strings.ToLower(line), "ms") {
            lastLine = line
        }
    }

    if lastLine == "" {
        return 0, fmt.Errorf("could not find statistics line in ping output")
    }

    // Regex to match the average time value. 
    // It looks for patterns like "Average = 42ms" or "min/avg/max/mdev = 10.2/12.3/14.5/2.1 ms"
    // This regex captures the number preceding "ms" in the average column.
    re := regexp.MustCompile(`(?i)average.*?(\d+(?:\.\d+)?)\s*ms|=\s*\d+(?:\.\d+)?/\s*(\d+(?:\.\d+)?)`)
    matches := re.FindStringSubmatch(lastLine)

    if len(matches) > 1 {
        // matches[1] is for "Average = X ms" format
        // matches[2] is for "min/avg/max/mdev = X/Y/Z/W ms" format
        var valStr string
        if matches[1] != "" {
            valStr = matches[1]
        } else if matches[2] != "" {
            valStr = matches[2]
        }

        if valStr != "" {
            val, err := strconv.ParseFloat(valStr, 64)
            if err == nil {
                return val, nil
            }
        }
    }

    // Fallback: Try to find any number followed by "ms" in the line
    // This is less precise but more robust against format variations
    fallbackRe := regexp.MustCompile(`(\d+(?:\.\d+)?)\s*ms`)
    fallbackMatches := fallbackRe.FindStringSubmatch(lastLine)
    if len(fallbackMatches) > 1 {
