package main

import (
	"bufio"
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency executes the ping command to the specified host
// a specified number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Determine the ping command flags based on the operating system.
	// Windows ping uses -n for count, Linux/Unix/macOS ping uses -c.
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Regex to extract time from ping output.
	// Matches "time=15ms" or "time=15.4 ms"
	re := regexp.MustCompile(`time[=<]([\d.]+)\s*ms`)

	// Execute the ping command
	cmd := exec.Command("ping", args...)
	var out bytes.Buffer
	cmd.Stdout = &out
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	// Parse the output to find latency values
	scanner := bufio.NewScanner(&out)
	var totalLatency float64
	var countFound int

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				totalLatency += latency
				countFound++
			}
		}
	}

	if countFound == 0 {
		return 0, errors.New("no latency data found in ping output")
	}

	return totalLatency / float64(countFound), nil
}

func main() {
	// Example usage for demonstration
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s (%d packets)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

