import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use direct arguments instead of shell execution to prevent command injection
	// and avoid shell interpretation of arguments.
	// The '-c' flag specifies the count, and we pass the host as a separate argument.
	// Note: On Windows, the ping command uses '-n' for count, but this implementation
	// is designed for Unix-like systems (Linux, macOS) as specified by the requirement to use 'ping'.
	// If cross-platform support is needed, the command and arguments should be adjusted based on runtime.GOOS.
	args := []string{"-c", strconv.Itoa(count), host}
	cmd := exec.Command("ping", args...)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// We do not include the raw output in the error message to avoid potential information leakage
		// or log injection if the output is not sanitized. The error from exec.Command is sufficient.
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Check for the standard Linux/macOS ping statistics line
		if strings.Contains(line, "rtt min/avg/max/mdev") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We use a non-capturing group for the fixed prefix and capture the average value.
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

