// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, errors.New("count must be a positive integer")
    }

    // Determine the ping command arguments based on the operating system.
    // We assume the standard flags are available on most Unix-like systems (Linux, macOS).
    // Windows ping uses different flags (e.g., -n for count), but for this example,
    // we focus on the common Unix syntax. If running on Windows, the command might fail
    // unless using a compatible environment (e.g., WSL or MinGW).
    args := []string{"-c", strconv.Itoa(count), host}

    cmd := exec.Command("ping", args...)

    output, err := cmd.CombinedOutput()
    if err != nil {
        // If the command fails, return the error along with the output for context
        return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, string(output))
    }

    // Parse the output to find the average latency.
    // We look for the line containing "avg/" in the statistics summary.
    // Example line: rtt min/avg/max/mdev = 0.045/0.060/0.075/0.015 ms
    scanner := bufio.NewScanner(strings.NewReader(string(output)))
    var avgLatency float64
    var found bool

    // Regex to match the average value in the statistics line.
    // It looks for "avg/" followed by a floating-point number.
    re := regexp.MustCompile(`avg/(\d+\.\d+)`)

    for scanner.Scan() {
        line := scanner.Text()
        if strings.Contains(line, "avg/") {
            matches := re.FindStringSubmatch(line)
            if len(matches) > 1 {
                val, err := strconv.ParseFloat(matches[1], 64)
                if err != nil {
                    return 0, fmt.Errorf("failed to parse latency value: %w", err)
                }
                avgLatency = val
                found = true
                break
            }
        }
    }

    if err := scanner.Err(); err != nil {
        return 0, fmt.Errorf("error reading ping output: %w", err)
    }

    if !found {
        return 0, errors.New("could not find average latency in ping output")
    }

    return avgLatency, nil
}

func main() {
    // Example usage of the MeasureLatency function.
    // In a real application, these values might come from command-line arguments or configuration.
    host := "8.8.8.8"
    count := 4

    fmt.Printf("Pinging %s %d times...\n", host, count)

    avg, err := MeasureLatency(host, count)
    if err != nil {
        fmt.Printf("Error measuring latency: %v\n", err)
        return
    }

    fmt.Printf("Average latency: %.3f ms\n", avg)
}

